import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import { db } from "../db";
import * as schema from "@shared/schema";
import { eq, and, inArray, desc, asc, type SQL } from "drizzle-orm";
